+		}
+
+		const res = await module.pool.query({
+			name: 'mget',
+			text: `
+SELECT o."_key" k, s."data" t
+  FROM "legacy_object_live" o
+ INNER JOIN "legacy_string" s
+         ON o."_key" = s."_key"
+        AND o."type" = s."type"
+ WHERE o."_key" = ANY($1::TEXT[])`,
+			values: [keys],
+		});
+
+		return keys.map(key => {
+			const row = res.rows.find(r => r.k === key);
+			return row ? row.t : null;
+		});
+	};
